css:
.wrapper.crm-pl-leadsrc {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --muted-strong: var(--color-gray-700, #C2C2CC);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --hair: rgba(255,255,255,.05);
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  box-sizing: border-box;
  container-type: inline-size;
  height: 100%;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  font-variant-numeric: tabular-nums;
}
.crm-pl-leadsrc .card,
.crm-pl-leadsrc .hd,
.crm-pl-leadsrc .hd-text,
.crm-pl-leadsrc .legend,
.crm-pl-leadsrc .canvas,
.crm-pl-leadsrc .empty { box-sizing: border-box; }

.crm-pl-leadsrc .card {
  display: flex;
  flex-direction: column;
  height: 100%;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px 18px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: border-color .16s ease, box-shadow .16s ease;
}
.crm-pl-leadsrc .card:hover {
  border-color: color-mix(in srgb, var(--accent) 30%, var(--line));
}

.crm-pl-leadsrc .hd {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 14px;
  padding-bottom: 12px;
  margin-bottom: 12px;
  border-bottom: 1px solid var(--hair);
}
.crm-pl-leadsrc .hd-text { min-width: 0; }
.crm-pl-leadsrc .eyebrow {
  margin: 0 0 5px;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--accent);
}
.crm-pl-leadsrc .title {
  margin: 0;
  font: 800 15px/1.25 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--ink);
  overflow-wrap: anywhere;
}
.crm-pl-leadsrc .sub {
  margin: 4px 0 0;
  font: 500 11px/1.35 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted);
}

.crm-pl-leadsrc .legend {
  display: flex;
  flex: 0 0 auto;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 6px 12px;
  padding-top: 2px;
}
.crm-pl-leadsrc .legend-item {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font: 600 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted-strong);
  white-space: nowrap;
}
.crm-pl-leadsrc .dot { width: 8px; height: 8px; border-radius: 2px; flex: 0 0 auto; }
.crm-pl-leadsrc .dot-amount { background: var(--accent); }
.crm-pl-leadsrc .dot-selected { background: var(--accent-2); }

.crm-pl-leadsrc .canvas { flex: 1; width: 100%; min-width: 0; min-height: 240px; }

.crm-pl-leadsrc .empty {
  margin: auto;
  padding: 24px 12px;
  text-align: center;
  color: var(--muted);
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

/* ---- responsive: container-query ladder (the block sizes to its own grid cell, not the viewport) ---- */
/* Chart-pair stacking at <=720px is a page-grid placement concern; inside this single chart the work
   is reflowing the header (the filter/legend wrap analog) and never letting the canvas collapse below
   the 220px spec floor. */
@container (max-width: 720px) {
  .crm-pl-leadsrc .card { padding: 15px 16px; }
}
@container (max-width: 560px) {
  .crm-pl-leadsrc .hd {
    flex-direction: column;
    align-items: flex-start;
    gap: 8px;
  }
  .crm-pl-leadsrc .legend { justify-content: flex-start; }
}
@container (max-width: 460px) {
  .crm-pl-leadsrc .card { padding: 14px; }
  .crm-pl-leadsrc .canvas { min-height: 220px; }
}
@container (max-width: 340px) {
  .crm-pl-leadsrc .legend { gap: 5px 10px; }
  .crm-pl-leadsrc .legend-item { font-size: 10.5px; }
}

@media (prefers-reduced-motion: reduce) {
  .crm-pl-leadsrc .card { transition: none; }
}
